import React from "react";

// Clean, minimalist tech badge component
const TechBadge = ({ name }) => <span className="tech-badge">{name}</span>;

export default function ArchitecturePanel() {
  return (
    <div
      className="architecture-panel"
      style={{ padding: "40px", maxWidth: "1200px", margin: "0 auto" }}
    >
      {/* ── Minimalist CSS for specific elements in this panel ── */}
      <style>{`
        .tech-badge {
          display: inline-block;
          padding: 6px 14px;
          border-radius: 20px;
          background: var(--bg-input);
          border: 1px solid var(--border-light);
          color: var(--text-primary);
          font-size: 12px;
          font-weight: 600;
          margin-right: 8px;
          margin-bottom: 8px;
          transition: all 0.2s ease;
        }

        .tech-badge:hover {
          background: var(--bg-card-hover);
          border-color: var(--accent-color);
          color: var(--accent-color);
        }

        .icon-box {
          width: 48px;
          height: 48px;
          border-radius: 12px;
          background: var(--bg-input);
          border: 1px solid var(--border-light);
          display: flex;
          align-items: center;
          justify-content: center;
          font-size: 24px;
        }

        .metrics-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
          gap: 24px;
          margin-bottom: 48px;
        }
      `}</style>

      <div
        className="panel-header"
        style={{ textAlign: "center", marginBottom: "48px" }}
      >
        <h2
          style={{ fontSize: "36px", fontWeight: "800", marginBottom: "12px" }}
        >
          System Architecture
        </h2>
        <p
          className="panel-sub"
          style={{
            margin: "0 auto",
            color: "var(--text-secondary)",
            maxWidth: "700px",
            lineHeight: "1.6",
          }}
        >
          A high-performance, syllabus-aware AI learning platform. Built with
          modern asynchronous frameworks and a locally vectorized
          Retrieval-Augmented Generation (RAG) pipeline.
        </p>
      </div>

      {/* ── Clean Tech Stack Grid ── */}
      <div className="metrics-grid">
        {/* Frontend Card */}
        <div
          className="advanced-card"
          style={{
            padding: "24px",
            border: "1px solid var(--border-light)",
            borderRadius: "16px",
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "16px",
              marginBottom: "20px",
            }}
          >
            <div className="icon-box">🎨</div>
            <h3
              className="card-title"
              style={{ fontSize: "20px", margin: 0, fontWeight: "700" }}
            >
              Frontend UI & State
            </h3>
          </div>
          <div style={{ marginBottom: "20px" }}>
            <TechBadge name="React 18" />
            <TechBadge name="Vite" />
            <TechBadge name="Zustand" />
            <TechBadge name="Framer Motion" />
          </div>
          <p
            style={{
              color: "var(--text-secondary)",
              fontSize: "14px",
              lineHeight: "1.7",
              margin: 0,
            }}
          >
            Lightning-fast SPA rendered via <strong>Vite</strong>. Global state
            is persisted using <strong>Zustand</strong>. Smooth UI transitions
            and Learning Velocity graphs are powered by{" "}
            <strong>Framer Motion</strong>.
          </p>
        </div>

        {/* Backend Card */}
        <div
          className="advanced-card"
          style={{
            padding: "24px",
            border: "1px solid var(--border-light)",
            borderRadius: "16px",
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "16px",
              marginBottom: "20px",
            }}
          >
            <div className="icon-box">⚙️</div>
            <h3
              className="card-title"
              style={{ fontSize: "20px", margin: 0, fontWeight: "700" }}
            >
              Backend API
            </h3>
          </div>
          <div style={{ marginBottom: "20px" }}>
            <TechBadge name="Python 3" />
            <TechBadge name="FastAPI" />
            <TechBadge name="Pydantic" />
          </div>
          <p
            style={{
              color: "var(--text-secondary)",
              fontSize: "14px",
              lineHeight: "1.7",
              margin: 0,
            }}
          >
            Driven by a highly concurrent <strong>FastAPI</strong> ASGI server.
            Endpoints enforce strict type-hinting and robust payload validation
            using <strong>Pydantic</strong> models.
          </p>
        </div>

        {/* Engine Card */}
        <div
          className="advanced-card"
          style={{
            padding: "24px",
            border: "1px solid var(--border-light)",
            borderRadius: "16px",
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "16px",
              marginBottom: "20px",
            }}
          >
            <div className="icon-box">🧠</div>
            <h3
              className="card-title"
              style={{ fontSize: "20px", margin: 0, fontWeight: "700" }}
            >
              AI & RAG Engine
            </h3>
          </div>
          <div style={{ marginBottom: "20px" }}>
            <TechBadge name="ChromaDB" />
            <TechBadge name="SentenceTransformers" />
            <TechBadge name="PyPDF" />
          </div>
          <p
            style={{
              color: "var(--text-secondary)",
              fontSize: "14px",
              lineHeight: "1.7",
              margin: 0,
            }}
          >
            Documents are chunked via <strong>PyPDF</strong> and vectorized into
            a local <strong>ChromaDB</strong> space to ground LLM generations
            strictly within the syllabus context.
          </p>
        </div>

        {/* Utilities Card */}
        <div
          className="advanced-card"
          style={{
            padding: "24px",
            border: "1px solid var(--border-light)",
            borderRadius: "16px",
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: "16px",
              marginBottom: "20px",
            }}
          >
            <div className="icon-box">🛠️</div>
            <h3
              className="card-title"
              style={{ fontSize: "20px", margin: 0, fontWeight: "700" }}
            >
              Parsing & Storage
            </h3>
          </div>
          <div style={{ marginBottom: "20px" }}>
            <TechBadge name="React Markdown" />
            <TechBadge name="KaTeX" />
            <TechBadge name="SQLite" />
            <TechBadge name="html2pdf.js" />
          </div>
          <p
            style={{
              color: "var(--text-secondary)",
              fontSize: "14px",
              lineHeight: "1.7",
              margin: 0,
            }}
          >
            Chat supports syntax highlighting and <strong>KaTeX</strong> math
            rendering. Dual <strong>SQLite</strong> databases manage multi-turn
            memory and learning analytics, with <strong>html2pdf</strong>{" "}
            enabling local exports.
          </p>
        </div>
      </div>

      {/* ── 5-Step RAG Data Pipeline Timeline ── */}
      <h3
        style={{
          fontSize: "28px",
          marginBottom: "32px",
          textAlign: "center",
          fontWeight: "800",
          color: "var(--text-primary)",
        }}
      >
        The RAG Data Pipeline
      </h3>

      <div
        className="advanced-card"
        style={{
          padding: "40px",
          border: "1px solid var(--border-light)",
          borderRadius: "16px",
        }}
      >
        <div className="timeline-container">
          {/* Step 1 */}
          <div
            className="timeline-item"
            style={{
              display: "flex",
              gap: "24px",
              paddingBottom: "40px",
              position: "relative",
            }}
          >
            <div
              className="timeline-line"
              style={{
                position: "absolute",
                left: "19px",
                top: "40px",
                bottom: 0,
                width: "2px",
                background: "var(--border-light)",
              }}
            ></div>
            <div
              className="step-number"
              style={{
                width: "40px",
                height: "40px",
                borderRadius: "50%",
                background: "var(--bg-sidebar)",
                border: "2px solid var(--accent-color)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontWeight: "bold",
                zIndex: 1,
                flexShrink: 0,
              }}
            >
              1
            </div>
            <div className="timeline-content">
              <h3
                className="timeline-title"
                style={{
                  fontSize: "18px",
                  fontWeight: "700",
                  marginBottom: "8px",
                }}
              >
                Document Ingestion & Chunking
              </h3>
              <p
                className="timeline-desc"
                style={{
                  color: "var(--text-secondary)",
                  lineHeight: "1.6",
                  margin: 0,
                }}
              >
                Syllabus files are parsed via PyPDF and split into overlapping
                chunks (e.g., 400 words). The algorithm uses overlap to ensure
                no context is lost between page breaks or paragraphs.
              </p>
            </div>
          </div>

          {/* Step 2 */}
          <div
            className="timeline-item"
            style={{
              display: "flex",
              gap: "24px",
              paddingBottom: "40px",
              position: "relative",
            }}
          >
            <div
              className="timeline-line"
              style={{
                position: "absolute",
                left: "19px",
                top: "40px",
                bottom: 0,
                width: "2px",
                background: "var(--border-light)",
              }}
            ></div>
            <div
              className="step-number"
              style={{
                width: "40px",
                height: "40px",
                borderRadius: "50%",
                background: "var(--bg-sidebar)",
                border: "2px solid var(--accent-color)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontWeight: "bold",
                zIndex: 1,
                flexShrink: 0,
              }}
            >
              2
            </div>
            <div className="timeline-content">
              <h3
                className="timeline-title"
                style={{
                  fontSize: "18px",
                  fontWeight: "700",
                  marginBottom: "8px",
                }}
              >
                Vector Embedding Generation
              </h3>
              <p
                className="timeline-desc"
                style={{
                  color: "var(--text-secondary)",
                  lineHeight: "1.6",
                  margin: 0,
                }}
              >
                Each text chunk is processed through a dense embedding model
                (like all-MiniLM-L6-v2) to convert the semantic meaning of the
                text into high-dimensional mathematical vector arrays.
              </p>
            </div>
          </div>

          {/* Step 3 */}
          <div
            className="timeline-item"
            style={{
              display: "flex",
              gap: "24px",
              paddingBottom: "40px",
              position: "relative",
            }}
          >
            <div
              className="timeline-line"
              style={{
                position: "absolute",
                left: "19px",
                top: "40px",
                bottom: 0,
                width: "2px",
                background: "var(--border-light)",
              }}
            ></div>
            <div
              className="step-number"
              style={{
                width: "40px",
                height: "40px",
                borderRadius: "50%",
                background: "var(--bg-sidebar)",
                border: "2px solid var(--accent-color)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontWeight: "bold",
                zIndex: 1,
                flexShrink: 0,
              }}
            >
              3
            </div>
            <div className="timeline-content">
              <h3
                className="timeline-title"
                style={{
                  fontSize: "18px",
                  fontWeight: "700",
                  marginBottom: "8px",
                }}
              >
                Vector Database Indexing
              </h3>
              <p
                className="timeline-desc"
                style={{
                  color: "var(--text-secondary)",
                  lineHeight: "1.6",
                  margin: 0,
                }}
              >
                The generated vectors, along with their original text metadata,
                are stored in a local ChromaDB instance optimized for
                ultra-fast, highly scalable similarity searches.
              </p>
            </div>
          </div>

          {/* Step 4 */}
          <div
            className="timeline-item"
            style={{
              display: "flex",
              gap: "24px",
              paddingBottom: "40px",
              position: "relative",
            }}
          >
            <div
              className="timeline-line"
              style={{
                position: "absolute",
                left: "19px",
                top: "40px",
                bottom: 0,
                width: "2px",
                background: "var(--border-light)",
              }}
            ></div>
            <div
              className="step-number"
              style={{
                width: "40px",
                height: "40px",
                borderRadius: "50%",
                background: "var(--bg-sidebar)",
                border: "2px solid var(--accent-color)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontWeight: "bold",
                zIndex: 1,
                flexShrink: 0,
              }}
            >
              4
            </div>
            <div className="timeline-content">
              <h3
                className="timeline-title"
                style={{
                  fontSize: "18px",
                  fontWeight: "700",
                  marginBottom: "8px",
                }}
              >
                Query Processing & Retrieval
              </h3>
              <p
                className="timeline-desc"
                style={{
                  color: "var(--text-secondary)",
                  lineHeight: "1.6",
                  margin: 0,
                }}
              >
                When a question is asked, it is converted into a vector. The
                engine performs a mathematical cosine-similarity search to fetch
                the top 3-5 most relevant chunks directly from the syllabus.
              </p>
            </div>
          </div>

          {/* Step 5 */}
          <div
            className="timeline-item"
            style={{ display: "flex", gap: "24px", position: "relative" }}
          >
            <div
              className="step-number"
              style={{
                width: "40px",
                height: "40px",
                borderRadius: "50%",
                background: "var(--bg-sidebar)",
                border: "2px solid var(--accent-color)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontWeight: "bold",
                zIndex: 1,
                flexShrink: 0,
              }}
            >
              5
            </div>
            <div className="timeline-content">
              <h3
                className="timeline-title"
                style={{
                  fontSize: "18px",
                  fontWeight: "700",
                  marginBottom: "8px",
                }}
              >
                LLM Synthesis & Generation
              </h3>
              <p
                className="timeline-desc"
                style={{
                  color: "var(--text-secondary)",
                  lineHeight: "1.6",
                  margin: 0,
                }}
              >
                The retrieved syllabus chunks are injected into the prompt
                alongside the query. The system uses this isolated context to
                generate a formatted, pointwise response without hallucinating.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useRef, useEffect } from "react";
import ReactMarkdown from "react-markdown";
import remarkMath from "remark-math";
import rehypeKatex from "rehype-katex";
import { Prism as SyntaxHighlighter } from "react-syntax-highlighter";
import { vscDarkPlus } from "react-syntax-highlighter/dist/esm/styles/prism";
import toast from "react-hot-toast";
import { askQuestion } from "../api";
import { useStore } from "../store";
import InteractiveQuiz from "./InteractiveQuiz";
import { useVoiceAssistant } from "../useVoice";
import html2pdf from "html2pdf.js";

const MODES = [
  { value: "quick", label: "Quick" },
  { value: "step-by-step", label: "Steps" },
  { value: "example-based", label: "Examples" },
  { value: "quiz", label: "Quiz" },
];

const SUGGESTIONS = [
  "Summarize the key concepts",
  "Generate a practice quiz",
  "Explain this to a beginner",
  "What are the practical applications?",
];

export default function ChatPanel() {
  const {
    session,
    messages,
    addMessage,
    level,
    setLevel,
    mode,
    setMode,
    subject,
    setActiveTopic,
    setRoadmapData,
  } = useStore();

  const [input, setInput] = useState("");
  const [loadingState, setLoadingState] = useState("");
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);

  const {
    isListening,
    startListening,
    speakText,
    stopSpeaking,
    autoSpeak,
    setAutoSpeak,
    isSpeaking,
  } = useVoiceAssistant();

  const userName = session?.student_name || "Ayushman";

  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good Morning";
    if (hour < 17) return "Good Afternoon";
    return "Good Evening";
  };

  const greeting = getGreeting();

  const handleVoiceInput = (transcript) => {
    setInput(transcript);
  };

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleTextareaChange = (e) => {
    setInput(e.target.value);
    e.target.style.height = "auto";
    e.target.style.height = `${Math.min(e.target.scrollHeight, 200)}px`;
  };

  const getExportHTML = (question, answer) => {
    const formatText = (text) =>
      String(text)
        .replace(/\n/g, "<br>")
        .replace(/\*\*(.*?)\*\*/g, "<b>$1</b>")
        .replace(/\*(.*?)\*/g, "<i>$1</i>");

    return `
      <div style="font-family: sans-serif; color: #000; padding: 20px; background: #fff;">
        <h2 style="color: #6b21a8; border-bottom: 1px solid #e5e5e5; padding-bottom: 10px;">NeuralNotes Q&A</h2>
        <h4 style="color: #333; margin-top: 20px;">Question:</h4>
        <div style="background: #f9f9f9; padding: 10px; border-radius: 5px; margin-bottom: 20px;">${formatText(question)}</div>
        <h4 style="color: #6b21a8;">Answer:</h4>
        <div style="background: #faf5ff; padding: 10px; border-radius: 5px;">${formatText(answer)}</div>
      </div>
    `;
  };

  const exportSingleToPDF = (question, answer) => {
    const htmlContent = getExportHTML(question, answer);
    const opt = {
      margin: 0.5,
      filename: `NeuralNotes_QnA_${new Date().getTime()}.pdf`,
      image: { type: "jpeg", quality: 0.98 },
      html2canvas: { scale: 2 },
      jsPDF: { unit: "in", format: "letter", orientation: "portrait" },
    };
    html2pdf().set(opt).from(htmlContent).save();
  };

  const exportSingleToDoc = (question, answer) => {
    let htmlContent = "<html><head><meta charset='utf-8'></head><body>";
    htmlContent += getExportHTML(question, answer);
    htmlContent += "</body></html>";

    const blob = new Blob(["\ufeff", htmlContent], {
      type: "application/msword",
    });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `StudyAI_QnA_${new Date().getTime()}.doc`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const sendMessage = async (overrideText = null) => {
    const userText =
      typeof overrideText === "string" ? overrideText : input.trim();
    if (!userText || !session || loadingState) return;

    if (
      userText.toLowerCase().includes("learn") ||
      userText.toLowerCase().includes("roadmap")
    ) {
      const topic =
        userText.replace(/learn|roadmap for/gi, "").trim() || "New Subject";
      setActiveTopic(topic);
      setRoadmapData([
        {
          title: "Basics & Foundations",
          duration: "3h",
          description: `Initial concepts of ${topic}.`,
        },
        {
          title: "Technical Application",
          duration: "5h",
          description: "Hands-on implementation and structure.",
        },
        {
          title: "Final Synthesis",
          duration: "4h",
          description: "Advanced integration and testing.",
        },
      ]);
    }

    addMessage({ role: "user", content: userText });

    // Progressive Loading
    setLoadingState("Searching syllabus...");
    const loadingInterval = setInterval(() => {
      setLoadingState((prev) => {
        if (prev === "Searching syllabus...") return "Analyzing context...";
        if (prev === "Analyzing context...") return "Synthesizing answer...";
        return "Synthesizing answer...";
      });
    }, 2500);

    try {
      let finalQuestion = `Answer this: "${userText}". RULES: Format STRICTLY Pointwise. Use the SAME language as the question. No Images. Convert table data into spaced bullet points.`;

      if (userText.toLowerCase().includes("quiz")) {
        finalQuestion = `Generate a multiple-choice quiz based on: "${userText}". You MUST return ONLY a raw JSON array. Format exactly like this: [{"question": "Question text?", "options": ["Option A", "Option B", "Option C", "Option D"], "correctAnswer": "Option A"}]`;
      }

      const payload = {
        question: finalQuestion,
        session_id: session.session_id,
        student_level: level,
        explanation_mode: "quick",
      };

      const data = await askQuestion(payload);
      const aiResponseText = String(
        data.answer || data.message || "Data not available.",
      );

      addMessage({
        role: "ai",
        content: aiResponseText,
        suggestions: data.follow_up_suggestions,
      });

      if (autoSpeak) {
        if (!aiResponseText.trim().startsWith("[")) {
          speakText(aiResponseText);
        }
        setAutoSpeak(false);
      }
    } catch (err) {
      toast.error("Failed to fetch answer.");
    } finally {
      clearInterval(loadingInterval);
      setLoadingState("");
      setInput("");
    }
  };

  const renderInputBox = () => (
    <div className="input-box-wrapper">
      <div className="input-core">
        <button
          className={`input-action-btn ${isListening ? "active-mic" : ""}`}
          onClick={() => startListening(handleVoiceInput)}
          disabled={!!loadingState || !session}
        >
          <svg
            viewBox="0 0 24 24"
            width="20"
            height="20"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
          >
            <path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3z"></path>
            <path d="M19 10v2a7 7 0 0 1-14 0v-2"></path>
            <line x1="12" y1="19" x2="12" y2="23"></line>
            <line x1="8" y1="23" x2="16" y2="23"></line>
          </svg>
        </button>

        {isSpeaking && (
          <button className="input-action-btn stop" onClick={stopSpeaking}>
            <svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor">
              <rect x="6" y="6" width="12" height="12"></rect>
            </svg>
          </button>
        )}

        <textarea
          ref={textareaRef}
          className="text-input"
          placeholder="Ask AI a question or make a request..."
          value={input}
          onChange={handleTextareaChange}
          onKeyDown={(e) =>
            e.key === "Enter" &&
            !e.shiftKey &&
            (e.preventDefault(), sendMessage())
          }
          rows={1}
          disabled={!session}
        />

        <button
          className="send-action-btn"
          onClick={() => sendMessage()}
          disabled={!!loadingState || !input.trim()}
          style={{
            opacity: !!loadingState || !input.trim() ? 0.3 : 1,
            background: input.trim()
              ? "var(--text-primary)"
              : "var(--border-light)",
            transition: "all 0.2s ease",
          }}
        >
          <svg
            viewBox="0 0 24 24"
            width="20"
            height="20"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
          >
            <line x1="12" y1="19" x2="12" y2="5"></line>
            <polyline points="5 12 12 5 19 12"></polyline>
          </svg>
        </button>
      </div>

      <div className="input-controls-row">
        <select
          className="clean-select"
          value={level}
          onChange={(e) => setLevel(e.target.value)}
        >
          <option value="beginner">Beginner</option>
          <option value="intermediate">Intermediate</option>
          <option value="advanced">Advanced</option>
        </select>

        <div className="clean-modes">
          {MODES.map((m) => (
            <button
