                                <path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path>
                              </svg>
                              Copy
                            </button>

                            <button
                              className="action-link"
                              onClick={() =>
                                exportSingleToPDF(
                                  idx > 0
                                    ? messages[idx - 1].content
